class Solution:
    def removeNthFromEnd(self, head, n):
        vals = []
        node = head
        while node:
            vals.append(node.val)
            node = node.next
        del vals[len(vals) - n]
        new = None
        for v in reversed(vals):
            new = ListNode(v, new)
        return new

