var removeNthFromEnd = function(head, n) {
    const dummy = new ListNode(0, head);
    let lead = dummy;
    for (let i = 0; i < n; i++) lead = lead.next;
    let trail = dummy;
    while (lead.next) {
        lead = lead.next;
        trail = trail.next;
    }
    trail.next = trail.next.next;
    return dummy.next;
};
